import styled, { css } from 'styled-components';
/* 단순 변수의 형태가 아니라 여러 줄의 스타일 구문을 조건부로 설정해야 하는 경우 css를 불러와야 함. */

/*  ``을 이용해 만든 문자열에 스타일 정보를 넣어줌. 이러한 문법을 Tagged템플릿 리터럴이라 함. */
/* styled-components를 사용하여 스타일링 된 엘리먼트를 만들때는 컴포넌트 파일의 상단에서 
styled를 불러오고 styled.태그명을 사용하여 구현 */

/*  해당 스타일이 적용된 div로 이루어진 리액트 컴포넌트가 생성됨.(스타일링된 엘리먼트)*/
const Box = styled.div` 
  /* props 로 넣어준 값을 직접 전달해줄 수 있습니다. */
  background: ${props => props.color || 'blue'}; /* 컬러를 주지 않았을 때는 blue가 적용되도록 */
  padding: 1rem;
  display: flex;

  /* 기본적으로 가로 크기 1024px에 가운데 정렬하고 768px미만이되면 꽉채우기 */
  width:1024px;
  margin:0 auto;
  @media (max-width:1024px){
    width:768px;
  }
  @media (max-width:768px){
    width:100%
  }


`;





/* div가아닌 button이나 input에 스타일링을 할 수도 있다. */
const Button = styled.button` 
  background: white;
  color: black;
  border-radius: 4px;
  padding: 0.5rem;
  display: flex;
  align-items: center;
  justify-content: center;
  box-sizing: border-box;
  font-size: 1rem;
  font-weight: 600;

  /* & 문자를 사용하여 Sass 처럼 자기 자신 선택 가능 */
  &:hover {
    background: rgba(255, 255, 255, 0.9);
  }

  /* 다음 코드는 inverted 값이 true 일 때 특정 스타일을 부여해줍니다. */
  /* props에 따른 조건부 스타일링 */
  ${props =>
    props.inverted &&
    css`   /* 조건부 스타일링시 반드시 css로 묶어줘야 함. */
      background: none;
      border: 2px solid white;
      color: white;
      &:hover {
        background: white;
        color: black;
      }
    `};
  & + button {
    margin-left: 1rem;
  }
`;

const StyledComponent = () => (
  <Box color="black">  {/* color값을 props로 넣어줌. */}
    <Button>안녕하세요</Button>
    <Button inverted={true}>테두리만</Button>
  </Box>
);

export default StyledComponent;