import { useReducer } from 'react';

//함수컴포넌트
function reducer(state, action) {
  //(저장될 값, 변경될값)
  return {
    ...state, //state복사본을 만들어
    [action.name]: action.value, //변경될 고유이름 name명의 변경될 내용을 input으로 보냄 (출력은 인풋에서)
  };
}

const Login = () => {
  //dispatch는 스토어의 내장 함수 중 하나로 리듀서에게 Action 을 발생하라고 시키는 것
  const [state, dispatch] = useReducer(reducer, {
    //변경된값을 state에 담아
    name: '', //엑션발생전 초기화 내용비우기
    nickname: '',
  });

  //비구조화할당이란 배열이나 객체의 속성 혹은 값을 해체하여 그 값을 변수에 각각 담아 사용하는 자바스크립트 표현식
  const { name, nickname } = state; //변경된 내용을 state에 담아 가져온 값을 각각 객체{name, nickname}에 전달.

  // onChange:내용변경함수.  onChangeName으로 변경된함수를 name에 저장
  const onChange = (e) => {
    //onChange이벤트가 발생하면 dispatch를 통해 엑션 발생
    dispatch(e.target);
  };

  return (
    <>
      <div className="layoutWrap">로그인 페이지</div>
      <div>
        {/* 인풋의 고유 name을 이용해 각각 내용을 변경함 */}
        <input name="name" value={name} onChange={onChange} />
        <input name="nickname" value={nickname} onChange={onChange} />
      </div>
      <div>
        <div>
          <b>이름 : </b> {name}
        </div>
        <div>
          <b>닉네임 : </b> {nickname}
        </div>
      </div>
    </>
  );
};

export default Login;
