/* header */
import { Container, Nav, Navbar } from 'react-bootstrap';
import 'bootstrap/dist/css/bootstrap.min.css';
import { Link, useNavigate, Outlet } from 'react-router-dom';

const Header = () => {
  let navigate = useNavigate();
  return (
    <>
      {/* header  */}
      <Navbar collapseOnSelect expand="lg" bg="dark" variant="dark" id="header">
        <Container>
          <Navbar.Brand href="/">
            <img src="../img/logo.png" alt="logo" width={200} />
          </Navbar.Brand>
          <Navbar.Toggle aria-controls="responsive-navbar-nav" />
          <Navbar.Collapse id="responsive-navbar-nav">
            <Nav className="me-auto">
              <Link to="/Company" className='navText'>카페파스쿠찌</Link>
              <Link className='navText'
                onClick={() => {
                  navigate('/Product');
                }}
              >
                메뉴
              </Link>
              <Link to="/Info"  className='navText'>매장안내</Link>
              <Link to="/Notice"className='navText' >공지사항</Link>
              <Link to="/Event" className='navText'>이벤트</Link>

              <Link className='navText'
                onClick={() => {
                  navigate(-1);
                }}
              >
                이전
              </Link>
              <Link className='navText'
                onClick={() => {
                  navigate(1);
                }}
              >
                다음
              </Link>
            </Nav>
            <Nav>
              <Link to="/Login"  className='navText'>login</Link>
              <Link to="/Mypage" className='navText'>mypage</Link>
            </Nav>
          </Navbar.Collapse>
        </Container>
      </Navbar>
    </>
  );
};

export default Header;
