import 'bootstrap/dist/css/bootstrap.min.css';
import { Container, Row, Col, Button } from 'react-bootstrap';
import { useParams } from 'react-router-dom';
import '../App.css';
import { useEffect, useState } from 'react';

const Detail = (props) => {
  useEffect(() => {
    console.log('안녕');
  });
  let [count, setCount] = useState(0);
  //App.js의 goods 데이터 전달 받음.
  let { id } = useParams();
  console.log(id);
  //.find()라는 문법을 사용하면 array자료안에서 원하는 항목만 찾을 수 있음.
  let choose = props.goods.find(function (a) {
    return a.id == id; //array자료.id == url에 입력한 번호와 같을 경우 변수 choose에 담아
  });
  return (
    <>
      <Container className="detailWrap">
        <Row>
          <Col sm={6}>
            {/*data.js의 이미지경로 */}
            <img src={choose.img} width="200" />
          </Col>
          <Col sm={4}>
            <h4>{choose.title}</h4> {/* 상품명 */}
            <p>{choose.content}</p> {/* 상품설명 */}
            <p>{choose.price}</p>
            <Button variant="danger">주문하기</Button>
          </Col>
        </Row>
      </Container>

      <div>
        {count}
        <button
          onClick={() => {
            setCount(count + 1);
          }}
        >
          버튼
        </button>
      </div>
    </>
  );
};

export default Detail;
